import socket

server_ip = '0.0.0.0'
server_port = 5555

player_list = ['Player1', 'Player2', 'Player3']
game_state = 'In progress'

def get_status():
    return f'Player List: {", ".join(player_list)}, Game State: {game_state}'

udp_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
udp_socket.bind((server_ip, server_port))

print('UDP Game Server is running...')

while True:
    data, addr = udp_socket.recvfrom(1024)
    status = get_status()
    udp_socket.sendto(status.encode(), addr)